"""Notion-like personal dashboard over the Balkan.works consumer shell."""

from __future__ import annotations

from superapp_v3 import render_superapp_page as render_v3


def render_superapp_page(language: str = "SR", initial_tab: str = "home", initial_module: str = "") -> str:
    page = render_v3(language, initial_tab, initial_module)
    page = page.replace("</style>", """.dashboard-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:14px}.dash-card{min-height:175px;border-radius:18px;padding:18px;color:#fff;text-decoration:none;display:flex;flex-direction:column;justify-content:end;box-shadow:var(--shadow);background:linear-gradient(135deg,#0d4036,#1b6652)}.dash-card.deals{background:linear-gradient(135deg,#bd4b27,#ff7b45)}.dash-card.money{background:linear-gradient(135deg,#34589b,#607cbd)}.dash-card.health{background:linear-gradient(135deg,#287b74,#4eb3a2)}.dash-card.auto{background:linear-gradient(135deg,#384557,#66798d)}.dash-card.local{background:linear-gradient(135deg,#73523a,#b88759)}.dash-card span{font-size:27px;margin-bottom:auto}.dash-card b{font-size:20px}.dash-card small{color:#eff7f3;margin-top:5px}.dashboard-tools{display:flex;gap:9px;align-items:center}.dashboard-tools button{border:1px solid var(--line);background:#fff;color:var(--pine);border-radius:10px;padding:9px 11px;font-weight:800}.module-order{display:flex;gap:7px;align-items:center;margin-top:8px}.module-order b{min-width:120px}.module-order button{border:1px solid var(--line);background:#fff;border-radius:8px;padding:4px 8px;color:var(--pine)}@media(max-width:980px){.dashboard-grid{grid-template-columns:repeat(2,1fr)}}@media(max-width:600px){.dashboard-grid{grid-template-columns:1fr}}</style>""", 1)
    dashboard = '''<section class="section" id="personal-dashboard"><div class="section-head"><div><div class="eyebrow">Tvoj dashboard</div><h2>Moduli koje si izabrao/la</h2></div><div class="dashboard-tools"><button data-view="profile">Uredi module</button></div></div><div class="dashboard-grid" id="module-dashboard-grid"><div class="empty">Prijavi se da sastaviš svoj Balkan.works dashboard.</div></div></section>'''
    marker = '<section class="section"><div class="section-head"><div><div class="eyebrow">Najčešće</div><h2>Šta ti treba danas?</h2>'
    page = page.replace(marker, dashboard + marker, 1)
    script = r'''<script>
const dashboardVisual={food:['🍎','Save Food','Ponude hrane u blizini','food'],deals:['🎁','Deals','Akcije, flajeri i kuponi','deals'],services:['🔧','Services','Majstori i lokalne usluge','services'],jobs:['💼','Jobs','Lokalni i freelance poslovi','jobs'],business:['▦','Business','Alati za tvoju firmu','business'],money:['⌘','Money','Wallet i finansijski alati','money'],auto:['🚗','Auto','Gorivo, parking i servis','auto'],health:['🩺','Health','Ordinacije i apoteke','health'],tickets:['🎟','Tickets','Podrška i zahtevi','tickets'],local:['◎','Balkan Local','Događaji u tvom kraju','local']};
function dashboardCard(module){const v=dashboardVisual[module.key]||['◉',module.name,'Balkan.works modul',''];return '<a class="dash-card '+v[3]+'" href="'+module.path+'"><span>'+v[0]+'</span><b>'+escProfile(module.name)+'</b><small>'+v[2]+'</small></a>'}
async function loadPersonalDashboard(){const section=document.getElementById('personal-dashboard'),grid=document.getElementById('module-dashboard-grid');if(!token()){section.style.display='none';return}try{const d=await api('/api/super-app/dashboard');const modules=d.modules||[];grid.innerHTML=modules.length?modules.map(dashboardCard).join(''):'<div class="empty" style="grid-column:1/-1">'+escProfile(d.empty_state)+'</div>';const staticGrid=document.querySelector('.feature-grid');if(staticGrid)staticGrid.closest('.section').style.display='none'}catch(e){grid.innerHTML='<div class="empty">'+escProfile(e.message)+'</div>'}}
async function saveDashboardOrder(keys){try{await api('/api/super-app/modules/layout',{method:'PUT',headers:{'content-type':'application/json'},body:JSON.stringify({module_keys:keys})});loadPersonalDashboard();setTimeout(enhanceModuleControls,80)}catch(e){document.getElementById('module-controls').innerHTML='<p>'+escProfile(e.message)+'</p>'}}
async function enhanceModuleControls(){if(!token())return;try{const d=await api('/api/super-app/profile'),active=d.active_modules||[],host=document.getElementById('module-controls');if(!host)return;host.innerHTML=active.length?active.map((item,index)=>'<div class="module-order"><b>'+escProfile(item.name)+'</b><button data-up="'+index+'" '+(index===0?'disabled':'')+'>↑</button><button data-down="'+index+'" '+(index===active.length-1?'disabled':'')+'>↓</button><button data-disable="'+item.key+'">Sakrij</button></div>').join(''):'<p>Izaberi module koje želiš da dodaš kroz Explore katalog.</p>';host.querySelectorAll('[data-up]').forEach(btn=>btn.onclick=()=>{const i=Number(btn.dataset.up),keys=active.map(x=>x.key);[keys[i-1],keys[i]]=[keys[i],keys[i-1]];saveDashboardOrder(keys)});host.querySelectorAll('[data-down]').forEach(btn=>btn.onclick=()=>{const i=Number(btn.dataset.down),keys=active.map(x=>x.key);[keys[i+1],keys[i]]=[keys[i],keys[i+1]];saveDashboardOrder(keys)});host.querySelectorAll('[data-disable]').forEach(btn=>btn.onclick=()=>moduleToggle(btn.dataset.disable,false))}catch(e){}}
document.querySelectorAll('[data-view="profile"]').forEach(btn=>btn.addEventListener('click',()=>setTimeout(enhanceModuleControls,180)));if(token()){loadPersonalDashboard();if(initial==='profile')setTimeout(enhanceModuleControls,220)}
</script>'''
    return page.replace("</body>", script + "</body>", 1)
